INSERT INTO controls (id, code, category, title, description, nis2_reference, recommended_evidence, recommended_action, weight) VALUES
('00000000-0000-0000-0000-000000000001','GOV-001','Governance','Maintain an information security policy','Document security expectations, ownership, and review cadence.','Management body oversight and cybersecurity risk-management measures.','Approved information security policy and review record.','Create or update an information security policy and assign an owner.',5),
('00000000-0000-0000-0000-000000000002','GOV-002','Governance','Assign cybersecurity responsibilities','Define accountable roles for cybersecurity risk and operations.','Governance and accountability for risk-management measures.','Security role descriptions or RACI matrix.','Assign named cybersecurity responsibilities and approval authority.',5),
('00000000-0000-0000-0000-000000000003','GOV-003','Governance','Review readiness with leadership','Leadership should periodically review cyber risks and remediation progress.','Management involvement in cybersecurity governance.','Meeting minutes or risk review deck.','Schedule recurring leadership readiness reviews.',4),
('00000000-0000-0000-0000-000000000004','RISK-001','Risk Management','Maintain cyber risk register','Track material cyber risks, owners, treatment decisions, and deadlines.','Risk analysis and information system security policies.','Risk register export.','Create a cyber risk register and review it monthly.',5),
('00000000-0000-0000-0000-000000000005','RISK-002','Risk Management','Define risk acceptance process','Document when risk may be accepted and by whom.','Risk treatment and governance decision evidence.','Risk acceptance form or approval log.','Define a risk acceptance workflow with expiry dates.',4),
('00000000-0000-0000-0000-000000000006','ASSET-001','Asset Management','Maintain asset inventory','Track important systems, owners, locations, and business criticality.','Security of network and information systems.','Asset inventory export.','Create and maintain an asset inventory for systems and data.',5),
('00000000-0000-0000-0000-000000000007','ASSET-002','Asset Management','Classify sensitive data','Identify sensitive business, personal, and operational data.','Protection of information assets.','Data classification register.','Classify key data sets and document handling requirements.',4),
('00000000-0000-0000-0000-000000000008','AC-001','Access Control','Enforce MFA for privileged accounts','Require MFA for administrators and high-risk accounts.','Access control and authentication security.','Identity provider MFA policy screenshot.','Enable MFA for privileged and remote access accounts.',5),
('00000000-0000-0000-0000-000000000009','AC-002','Access Control','Review user access regularly','Review user accounts, privileges, and leaver access.','Access control lifecycle measures.','Access review export and approvals.','Run quarterly access reviews and remove stale access.',4),
('00000000-0000-0000-0000-000000000010','AC-003','Access Control','Apply least privilege','Limit administrative rights to documented business need.','Access control and privilege management.','Admin group membership export.','Reduce standing admin access and document exceptions.',5),
('00000000-0000-0000-0000-000000000011','IR-001','Incident Handling','Maintain incident response procedure','Document detection, escalation, containment, communication, and review steps.','Incident handling and response measures.','Incident response procedure.','Approve an incident response procedure and test it.',5),
('00000000-0000-0000-0000-000000000012','IR-002','Incident Handling','Define incident escalation process','Clarify who is notified internally and when.','Incident management and reporting readiness.','Escalation matrix.','Create an escalation matrix and emergency contact list.',4),
('00000000-0000-0000-0000-000000000013','IR-003','Incident Handling','Perform post-incident reviews','Capture lessons learned after security incidents or exercises.','Incident response improvement cycle.','Post-incident review notes.','Run post-incident reviews and track follow-up actions.',4),
('00000000-0000-0000-0000-000000000014','BC-001','Business Continuity','Document business continuity plan','Define continuity objectives for critical services.','Business continuity and crisis management.','Business continuity plan.','Document continuity plans for key services.',5),
('00000000-0000-0000-0000-000000000015','BC-002','Business Continuity','Test continuity arrangements','Exercise continuity procedures periodically.','Continuity testing and resilience measures.','Exercise report.','Run a continuity tabletop exercise and record results.',4),
('00000000-0000-0000-0000-000000000016','BCK-001','Backup and Disaster Recovery','Perform backup restore tests','Verify backups can be restored within recovery expectations.','Backup management and disaster recovery.','Backup restore test report.','Test restoration for critical systems and fix failures.',5),
('00000000-0000-0000-0000-000000000017','BCK-002','Backup and Disaster Recovery','Protect backup access','Restrict and monitor access to backup systems.','Security of backup and recovery environments.','Backup admin access list.','Review backup privileges and enable MFA.',4),
('00000000-0000-0000-0000-000000000018','SUP-001','Supply Chain Security','Maintain supplier security review process','Assess cyber risks from important suppliers and service providers.','Supply chain security measures.','Supplier assessment questionnaire.','Review critical suppliers and document cyber requirements.',5),
('00000000-0000-0000-0000-000000000019','SUP-002','Supply Chain Security','Track supplier security clauses','Include security expectations in supplier agreements where appropriate.','Supplier relationship cybersecurity expectations.','Contract clause checklist.','Review supplier contracts for security obligations.',4),
('00000000-0000-0000-0000-000000000020','VM-001','Vulnerability Management','Track vulnerabilities and remediation','Record vulnerabilities, severity, owners, and remediation deadlines.','Vulnerability handling and disclosure measures.','Vulnerability tracker export.','Implement a vulnerability remediation tracker.',5),
('00000000-0000-0000-0000-000000000021','VM-002','Vulnerability Management','Patch critical systems promptly','Define patch timelines based on risk.','Security maintenance and vulnerability remediation.','Patch compliance report.','Define and monitor patch SLAs for critical systems.',5),
('00000000-0000-0000-0000-000000000022','SDM-001','Secure Development and Maintenance','Review changes before release','Security-relevant changes should be reviewed and traceable.','Secure development and maintenance.','Change approval record.','Add security checks to change and release workflows.',4),
('00000000-0000-0000-0000-000000000023','SDM-002','Secure Development and Maintenance','Protect production secrets','Store credentials securely and rotate when needed.','Secure configuration and credential protection.','Secrets management policy or vault evidence.','Move secrets into a controlled secret store.',5),
('00000000-0000-0000-0000-000000000024','HY-001','Cyber Hygiene','Harden endpoint configuration','Apply baseline security settings to laptops, servers, and mobile devices.','Basic cyber hygiene and secure configuration.','Endpoint baseline or MDM policy.','Define and deploy endpoint hardening baselines.',4),
('00000000-0000-0000-0000-000000000025','HY-002','Cyber Hygiene','Maintain malware protection','Use managed protection on endpoints and servers.','Basic cybersecurity hygiene.','Protection console screenshot.','Deploy and monitor endpoint protection coverage.',4),
('00000000-0000-0000-0000-000000000026','TRN-001','Security Training','Provide awareness training','Train employees on phishing, reporting, passwords, and data handling.','Cyber hygiene and training.','Training attendance list.','Run annual awareness training and track attendance.',4),
('00000000-0000-0000-0000-000000000027','CRY-001','Cryptography and Encryption','Maintain encryption policy','Define encryption expectations for data at rest and in transit.','Cryptography and encryption measures.','Encryption policy and system settings.','Approve encryption requirements for key systems.',4),
('00000000-0000-0000-0000-000000000028','LOG-001','Logging and Monitoring','Log security-relevant events','Collect important logs for identity, endpoints, servers, and applications.','Monitoring, detection, and logging measures.','Logging configuration export.','Enable security event logging for critical services.',5),
('00000000-0000-0000-0000-000000000029','LOG-002','Logging and Monitoring','Review alerts and detections','Define who reviews security alerts and how escalations happen.','Incident detection and response readiness.','Alert triage process.','Assign alert review responsibility and escalation steps.',4),
('00000000-0000-0000-0000-000000000030','MFA-001','MFA and Authentication','Require strong authentication for remote access','Remote access should use MFA and secure authentication methods.','Authentication security and access control.','VPN or SSO configuration screenshot.','Enable MFA for remote access and disable weak methods.',5),
('00000000-0000-0000-0000-000000000031','POL-001','Policy Management','Review policies annually','Policies should be current, owned, and reviewed.','Governance and documented policies.','Policy review log.','Create a policy review calendar and owner list.',3),
('00000000-0000-0000-0000-000000000032','POL-002','Policy Management','Communicate policies to employees','Employees should know where relevant policies are and acknowledge key rules.','Cyber hygiene and governance communication.','Policy acknowledgement records.','Publish policies and track employee acknowledgement.',3);
INSERT INTO policy_templates (id, name, category, content, disclaimer) VALUES
('10000000-0000-0000-0000-000000000001','Information Security Policy','Governance','Purpose: define the organization approach to protecting systems and information.\nScope: employees, contractors, systems, data, and suppliers.\nRequirements: assign responsibilities, manage risks, review controls, and maintain evidence.','Template for internal preparation only. Review with a qualified advisor before official adoption.'),
('10000000-0000-0000-0000-000000000002','Incident Response Policy','Incident Handling','Purpose: define how incidents are detected, escalated, contained, documented, and reviewed.\nInclude: owner assignment, evidence preservation, management notification, and post-incident review.','Template for internal preparation only. Review with a qualified advisor before official adoption.'),
('10000000-0000-0000-0000-000000000003','Access Control Policy','Access Control','Purpose: manage user access through least privilege, MFA, joiner-mover-leaver controls, and periodic access reviews.','Template for internal preparation only. Review with a qualified advisor before official adoption.'),
('10000000-0000-0000-0000-000000000004','Backup and Recovery Policy','Backup and Disaster Recovery','Purpose: define backup frequency, protection, restore testing, recovery responsibilities, and retention expectations.','Template for internal preparation only. Review with a qualified advisor before official adoption.'),
('10000000-0000-0000-0000-000000000005','Supplier Security Policy','Supply Chain Security','Purpose: evaluate and manage cybersecurity risk from important suppliers and managed service providers.','Template for internal preparation only. Review with a qualified advisor before official adoption.'),
('10000000-0000-0000-0000-000000000006','Acceptable Use Policy','Cyber Hygiene','Purpose: describe acceptable use of company devices, networks, data, email, internet, and collaboration tools.','Template for internal preparation only. Review with a qualified advisor before official adoption.'),
('10000000-0000-0000-0000-000000000007','Password and MFA Policy','MFA and Authentication','Purpose: define password, MFA, privileged account, and remote access authentication requirements.','Template for internal preparation only. Review with a qualified advisor before official adoption.'),
('10000000-0000-0000-0000-000000000008','Vulnerability Management Policy','Vulnerability Management','Purpose: identify, prioritize, remediate, and verify vulnerabilities across systems and applications.','Template for internal preparation only. Review with a qualified advisor before official adoption.'),
('10000000-0000-0000-0000-000000000009','Business Continuity Plan','Business Continuity','Purpose: define continuity arrangements for critical services, people, technology, suppliers, and communications.','Template for internal preparation only. Review with a qualified advisor before official adoption.'),
('10000000-0000-0000-0000-000000000010','Security Training Policy','Security Training','Purpose: ensure employees receive cybersecurity awareness training and know how to report suspected incidents.','Template for internal preparation only. Review with a qualified advisor before official adoption.');
